#include<bits/stdc++.h>
#define ll long long
using namespace std;
struct node{
	int num,val,x;
    bool operator < (const node &a) const {
        return a.val<val;
    }
};const int MAXN=1e5+5;
int n,a[MAXN],b[MAXN];
priority_queue<node> q;
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d",&n);
	for(int i=1;i<=n;++i)scanf("%d",a+i);
	for(int i=1;i<=n;++i)scanf("%d",b+i);
	for(int i=1;i<=n;++i)q.push({i,a[i]+b[1],1});
	for(int i=0;i<n;++i){
		printf("%d ",q.top().val);q.push({q.top().num,a[q.top().num]+b[q.top().x+1],q.top().x+1});q.pop();
	}
	return false;
}
